    print(snack["name"])
</code></pre> <pre><code>fetch("http://127.0.0.1:8000/snacks/")
  .then((response) =&gt; {
    if (!response.ok) {
      throw new Error("La solicitud falló");
    }

    return response.json();
  })
  .then((snacks) =&gt; {
    snacks.forEach((snack) =&gt; {
      console.log(snack.name);
    });
  })
  .catch((error) =&gt; {
    console.error(error);
  });
