PythonJavaScriptcURL <pre><code>import requests

new_snack = {
    "name": "Plutonian Ice Cream",
    "price": 8.75,
    "planet_of_origin": "Pluto",
    "is_radioactive": False,
}

response = requests.post(
    "http://127.0.0.1:8000/snacks/",
    json=new_snack,
    timeout=10,
)

response.raise_for_status()

print(response.json())
</code></pre> <pre><code>const newSnack = {
  name: "Plutonian Ice Cream",
  price: 8.75,
  planet_of_origin: "Pluto",
  is_radioactive: false
};

fetch("http://127.0.0.1:8000/snacks/", {
  method: "POST",
  headers: {
    "Content-Type": "application/json"
  },
  body: JSON.stringify(newSnack)
})
  .then((response) =&gt; response.json())
  .then((snack) =&gt; console.log(snack))
  .catch((error) =&gt; console.error(error));
</code></pre> <pre><code>curl -X POST http://127.0.0.1:8000/snacks/ \
